                                            <span className="username">Chris_Veal</span>
                                            <span className="timestamp">4 years 9 months ago</span>
                                        </div>
                                        <a href="#" className="reply-title">Manual upload of MRLcomm.ino</a>
                                        <div className="post">
                                            <p>Kevin,</p>
                                            <p>Many thanks, I have done that and it seemed to work ok - I opened the MRLcomm.ino file from Arduino IDE and then uploaded it (couple of warnings but that's all). I now need to learn enough to try and communicate with the Arduino from MyRobotLab.</p>
                                            <p>Thanks again for your help.</p>
                                            <p>Chris</p>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="footer-text">
                                <a href="#">Getting Started</a>
                                <p style={{marginTop: '20px', color: '#999'}}>
                                    <a href="#">Log in</a> or <a href="#">register</a> to post comments
                                </p>
                            </div>
                        </div>
                        <div className="site-footer"></div>
                    </div>
                </div>
            );
        }

        function Sidebar() {
            return (
