                        <a href="#">Download</a>
                        <a href="#">FAQs</a>
                        <a href="#">Forums</a>
                    </div>
                    <div className="login-area">
                        <a href="#">Log in</a>
                    </div>
                </div>
            );
        }

        const root = ReactDOM.createRoot(document.getElementById('root'));
        root.render(<App />);
    </script>
</body>
